import{z as t}from"zod";export const AssetKindSchema=t.enum(["character","scene","prop"]),AssetSchema=t.object({id:t.string().min(1),kind:AssetKindSchema,name:t.string().min(1),aliases:t.array(t.string().min(1)).default([]),description:t.string().default(""),firstChapter:t.number().int().min(1).default(1),lastChapter:t.number().int().min(1).default(1),attributes:t.record(t.string(),t.string()).default({}),appearanceCount:t.number().int().min(1).default(1)}).refine(e=>e.lastChapter>=e.firstChapter,{message:"lastChapter must be >= firstChapter",path:["lastChapter"]}),AssetCatalogSchema=t.object({characters:t.array(AssetSchema).default([]),scenes:t.array(AssetSchema).default([]),props:t.array(AssetSchema).default([])});export function emptyCatalog(){return AssetCatalogSchema.parse({})}
